/// <summary>
/// Extension of the <c>SalesLine</c> data source in the <c>SalesTable</c> form for the ETGSPAIN model.
/// </summary>
[ExtensionOf(formDataSourceStr(SalesTable, SalesLine))]
final class SalesTable_SalesLine_ETGSPAIN_FormDataSource_Extension
{
}

Method.Source:
/// <summary>
/// Extension of the <c>active</c> method.
/// </summary>
/// <returns>Returns an integer indicating the result of the operation.</returns>
int active()
{
    int ret = next active();

    FormControl formControl = this.formRun().design().controlName(formControlStr(SalesTable, ETGSPAINUnsoldInventTransModifyController));
    if(CompanyInfo::find().ETGSpanishCompany == NoYes::Yes)
    {
        if (FormControl.isVisible())
        {
            SalesLine salesLine = this.cursor() as SalesLine;
            formControl.enabled(ETGSPAINUnsoldInventTrans::findByInventTransId(salesLine.InventTransId, true).RecId ? true : false);
        }
    }

    return ret;
}
